  1→//! Input generation strategy trait and adaptive meta-strategy.
  2→//!
  3→//! Each input source (literals, boundary seeds, pool, random, Z3 solver, fuzzer,
  4→//! user-provided) implements [`InputStrategy`]. The [`MetaStrategy`] selects
  5→//! among registered strategies using outcome-based adaptive scoring.
  6→
  7→use serde_json::Value;
  8→
  9→use crate::boundary_dict::generate_boundary_inputs;
 10→use crate::input_gen::{crossover_inputs, generate_random_inputs, literals_to_candidate_inputs, mutate_inputs};
 11→use crate::orchestrator::fuzz_inputs;
 12→use crate::execution_record::SymConstraint;
 13→use crate::orchestrator::FrontendCapabilities;
 14→use crate::protocol::{ExecuteResult, LiteralValue};
 15→use crate::solver::{self, SolveResult};
 16→use crate::sym_expr::SymExpr;
 17→use crate::types::{ParamInfo, TypeInfo};
 18→
 19→// ---------------------------------------------------------------------------
 20→// Strategy context — shared read-only state available to all strategies
 21→// ---------------------------------------------------------------------------
 22→
 23→/// Read-only context passed to strategies on each `next()` call.
 24→///
 25→/// Contains the function's type signature, extracted literals, and frontend
 26→/// capabilities so strategies can generate type-appropriate inputs without
 27→/// holding references to the full analysis.
 28→pub struct StrategyContext {
 29→    /// Parameter names and types for the function under exploration.
 30→    pub params: Vec<ParamInfo>,
 31→    /// Literal constants extracted from the function body by static analysis.
 32→    pub literals: Vec<LiteralValue>,
 33→    /// Frontend capabilities (used to gate complex-type generation).
 34→    pub capabilities: FrontendCapabilities,
 35→}
 36→
 37→impl StrategyContext {
 38→    /// Convenience: extract just the `TypeInfo` for each parameter.
 39→    pub fn param_types(&self) -> Vec<TypeInfo> {
 40→        self.params.iter().map(|p| p.typ.clone()).collect()
 41→    }
 42→}
 43→
 44→// ---------------------------------------------------------------------------
 45→// InputStrategy trait
 46→// ---------------------------------------------------------------------------
 47→
 48→/// A composable input generation strategy.
 49→///
 50→/// Strategies produce candidate input vectors and optionally react to execution
 51→/// feedback. The [`MetaStrategy`] polls strategies by adaptive priority and
 52→/// fans out feedback to all registered strategies after each execution.
 53→pub trait InputStrategy: Send {
 54→    /// Produce the next candidate input vector, or `None` if exhausted.
 55→    fn next(&mut self, ctx: &StrategyContext) -> Option<Vec<Value>>;
 56→
 57→    /// Receive feedback from an execution result.
 58→    ///
 59→    /// Strategies that don't use feedback (literals, random, etc.) leave the
 60→    /// default no-op implementation. Reactive strategies (Z3 solver, fuzzer)
 61→    /// override this to record constraints or interesting values.
 62→    fn feedback(&mut self, _inputs: &[Value], _result: &ExecuteResult, _was_new_path: bool) {}
 63→
 64→    /// Human-readable strategy name, used for discovery attribution and config keys.
 65→    fn name(&self) -> &str;
 66→
 67→    /// Total number of candidates this strategy will ever produce, if known.
 68→    ///
 69→    /// Returns `Some(n)` for exhaustible strategies (boundary seeds, literals,
 70→    /// pool, user-provided) and `None` for infinite strategies (random, fuzzer,
 71→    /// Z3 solver).
 72→    fn estimated_size(&self) -> Option<u64> {
 73→        None
 74→    }
 75→}
 76→
 77→// ---------------------------------------------------------------------------
 78→// UserProvidedStrategy — yields a pre-built list of candidate inputs
 79→// ---------------------------------------------------------------------------
 80→
 81→/// Strategy that yields user-provided candidate inputs in order.
 82→///
 83→/// Exhaustible: returns `None` once all candidates have been yielded.
 84→/// Feedback is ignored — the input list is fixed at construction time.
 85→pub struct UserProvidedStrategy {
 86→    inputs: Vec<Vec<Value>>,
 87→    index: usize,
 88→}
 89→
 90→impl UserProvidedStrategy {
 91→    pub fn new(inputs: Vec<Vec<Value>>) -> Self {
 92→        Self { inputs, index: 0 }
 93→    }
 94→}
 95→
 96→impl InputStrategy for UserProvidedStrategy {
 97→    fn next(&mut self, _ctx: &StrategyContext) -> Option<Vec<Value>> {
 98→        if self.index < self.inputs.len() {
 99→            let v = self.inputs[self.index].clone();
100→            self.index += 1;
101→            Some(v)
102→        } else {
103→            None
104→        }
105→    }
106→
107→    fn name(&self) -> &str {
108→        "user_provided"
109→    }
110→
111→    fn estimated_size(&self) -> Option<u64> {
112→        Some(self.inputs.len() as u64)
113→    }
114→}
115→
116→// ---------------------------------------------------------------------------
117→// LiteralsStrategy — exhaustible strategy yielding literal-derived inputs
118→// ---------------------------------------------------------------------------
119→
120→/// Yields inputs derived from literals extracted during static analysis.
121→///
122→/// Pre-computes candidates via [`literals_to_candidate_inputs`] at construction
123→/// time, then yields them one at a time. Does not apply any budget cap — that
124→/// is the meta-strategy's responsibility.
125→pub struct LiteralsStrategy {
126→    candidates: Vec<Vec<Value>>,
127→    cursor: usize,
128→}
129→
130→impl LiteralsStrategy {
131→    pub fn new(params: &[ParamInfo], literals: &[LiteralValue]) -> Self {
132→        Self {
133→            candidates: literals_to_candidate_inputs(params, literals),
134→            cursor: 0,
135→        }
136→    }
137→}
138→
139→impl InputStrategy for LiteralsStrategy {
140→    fn next(&mut self, _ctx: &StrategyContext) -> Option<Vec<Value>> {
141→        if self.cursor < self.candidates.len() {
142→            let v = self.candidates[self.cursor].clone();
143→            self.cursor += 1;
144→            Some(v)
145→        } else {
146→            None
147→        }
148→    }
149→
150→    fn name(&self) -> &str {
151→        "literals"
152→    }
153→
154→    fn estimated_size(&self) -> Option<u64> {
155→        Some(self.candidates.len() as u64)
156→    }
157→}
