    // -----------------------------------------------------------------------
    // MetaStrategy property tests
    // -----------------------------------------------------------------------

    mod meta_proptests {
        use super::*;
        use proptest::prelude::*;
        use proptest::collection::vec as pvec;

        /// Arbitrary MetaConfig with valid ranges.
        fn arb_meta_config() -> impl Strategy<Value = MetaConfig> {
            (
                10..200usize,       // window_size
                1..50u64,           // cold_start_threshold
                1..5u32,            // floor percentage (1-5%)
                any::<bool>(),      // adaptive
            )
                .prop_map(|(window_size, cold_start_threshold, floor_pct, adaptive)| {
                    MetaConfig {
                        window_size,
                        cold_start_threshold,
                        floor: floor_pct as f64 / 100.0,
                        adaptive,
                        static_weights: None,
                    }
                })
        }

        /// Build a MetaStrategy with N InfiniteStrategies, each with a
        /// randomized outcome history.
        fn build_meta_with_history(
            n_strategies: usize,
            config: MetaConfig,
            outcomes: &[Vec<bool>],
            supplied_counts: &[u64],
        ) -> MetaStrategy {
            let strategies: Vec<Box<dyn InputStrategy>> = (0..n_strategies)
                .map(|i| {
                    let name: &'static str = match i % 4 {
                        0 => "alpha",
                        1 => "beta",
                        2 => "gamma",
                        _ => "delta",
                    };
                    Box::new(InfiniteNamedStrategy {
                        name,
                        value: vec![Value::from(i as i64)],
                    }) as Box<dyn InputStrategy>
                })
                .collect();

            let mut meta = MetaStrategy::new(strategies, config);

            // Apply supplied counts and outcome windows.
            for (i, state) in meta.states.iter_mut().enumerate() {
                if i < supplied_counts.len() {
                    state.total_supplied = supplied_counts[i];
                }
                if i < outcomes.len() {
                    state.window = outcomes[i].iter().copied().collect();
                }
            }

            meta
        }

        /// Infinite strategy with configurable name.
        struct InfiniteNamedStrategy {
            name: &'static str,
            value: Vec<Value>,
        }

        impl InputStrategy for InfiniteNamedStrategy {
            fn next(&mut self, _ctx: &StrategyContext) -> Option<Vec<Value>> {
                Some(self.value.clone())
            }

            fn name(&self) -> &str {
                self.name
            }
        }

        proptest! {
            #![proptest_config(ProptestConfig::with_cases(100))]

            /// Normalized allocations from compute_scores always sum to 1.0
            /// (within floating-point tolerance) when there are non-exhausted strategies.
            #[test]
            fn allocations_sum_to_one(
                n in 1..6usize,
                config in arb_meta_config(),
                outcomes in pvec(pvec(any::<bool>(), 0..50), 1..6),
                supplied in pvec(0..200u64, 1..6),
            ) {
                let n = n.min(outcomes.len()).min(supplied.len());
                let config = MetaConfig { adaptive: true, ..config };
                let meta = build_meta_with_history(n, config, &outcomes[..n], &supplied[..n]);

                let scores = meta.compute_scores();
                if scores.is_empty() {
                    return Ok(());
                }

                let total: f64 = scores.iter().map(|(_, s)| s).sum();
                // Normalize and verify sum.
                let normalized_sum: f64 = scores.iter().map(|(_, s)| s / total).sum();
                prop_assert!(
                    (normalized_sum - 1.0).abs() < 1e-10,
                    "normalized allocations must sum to 1.0, got {}",
                    normalized_sum
                );
            }

            /// Floor is respected: every non-exhausted strategy's raw score
            /// is >= the configured floor.
            #[test]
            fn floor_respected_for_all_non_exhausted(
                n in 1..6usize,
                config in arb_meta_config(),
                outcomes in pvec(pvec(any::<bool>(), 0..100), 1..6),
                supplied in pvec(0..200u64, 1..6),
            ) {
                let n = n.min(outcomes.len()).min(supplied.len());
                let config = MetaConfig { adaptive: true, ..config };
                let meta = build_meta_with_history(n, config.clone(), &outcomes[..n], &supplied[..n]);

                let scores = meta.compute_scores();
                for &(_, score) in &scores {
                    prop_assert!(
                        score >= config.floor - 1e-15,
                        "score {} is below floor {}",
                        score,
                        config.floor
                    );
                }
            }

            /// Exhausted strategies never appear in compute_scores output.
            #[test]
            fn exhausted_strategies_get_zero_allocation(
                n in 2..6usize,
                config in arb_meta_config(),
                outcomes in pvec(pvec(any::<bool>(), 0..50), 2..6),
                supplied in pvec(0..200u64, 2..6),
                exhaust_idx in 0..5usize,
            ) {
                let n = n.min(outcomes.len()).min(supplied.len());
                let config = MetaConfig { adaptive: true, ..config };
                let mut meta = build_meta_with_history(n, config, &outcomes[..n], &supplied[..n]);

                let exhaust_idx = exhaust_idx % n;
                meta.states[exhaust_idx].exhausted = true;

                let scores = meta.compute_scores();
                for &(idx, _) in &scores {
                    prop_assert_ne!(
                        idx,
                        exhaust_idx,
                        "exhausted strategy {} should not appear in scores",
                        exhaust_idx
                    );
                }
            }

            /// Cold-start strategies get the average score of graduated strategies.
            /// If all strategies are cold-start, they all get 1.0 (clamped by floor).
            #[test]
            fn cold_start_gets_average_of_graduated(
                config in arb_meta_config(),
                graduated_outcomes in pvec(any::<bool>(), 1..50),
            ) {
                let config = MetaConfig {
                    adaptive: true,
                    cold_start_threshold: 20,
                    ..config
                };

                // Two strategies: one graduated (supplied >= 20), one cold-start (supplied < 20).
                let graduated_window: Vec<bool> = graduated_outcomes;
                let mut meta = build_meta_with_history(
                    2,
                    config.clone(),
                    &[graduated_window.clone(), vec![]],
                    &[25, 0], // 25 >= 20 (graduated), 0 < 20 (cold-start)
                );

                let scores = meta.compute_scores();
                prop_assert_eq!(scores.len(), 2);

                let graduated_score = scores.iter().find(|(idx, _)| *idx == 0).unwrap().1;
                let cold_start_score = scores.iter().find(|(idx, _)| *idx == 1).unwrap().1;

                // The graduated hit rate.
                let expected_hit_rate = hit_rate(&graduated_window.iter().copied().collect());
                let expected_graduated = expected_hit_rate.max(config.floor);
                let expected_cold = expected_hit_rate.max(config.floor);

                prop_assert!(
                    (graduated_score - expected_graduated).abs() < 1e-10,
                    "graduated score {} != expected {}",
                    graduated_score,
                    expected_graduated
                );
                prop_assert!(
                    (cold_start_score - expected_cold).abs() < 1e-10,
                    "cold-start score {} != expected average {}",
                    cold_start_score,
                    expected_cold
                );
            }

            /// All-cold-start: when no strategy is graduated, all get score 1.0
            /// (clamped to at least floor).
            #[test]
            fn all_cold_start_gives_one(
                n in 1..5usize,
                config in arb_meta_config(),
            ) {
                let config = MetaConfig {
                    adaptive: true,
                    cold_start_threshold: 100, // high threshold so all are cold-start
                    ..config
                };
                let meta = build_meta_with_history(
                    n,
                    config.clone(),
                    &vec![vec![]; n],
                    &vec![0; n],
                );

                let scores = meta.compute_scores();
                prop_assert_eq!(scores.len(), n);
                for &(_, score) in &scores {
                    // 1.0 >= any floor in [0.01, 0.05], so score should be exactly 1.0.
                    prop_assert!(
                        (score - 1.0).abs() < 1e-10,
                        "all-cold-start score should be 1.0, got {}",
                        score
                    );
                }
            }

            /// Round-robin mode produces candidates from each non-exhausted
            /// strategy before repeating.
            #[test]
            fn round_robin_visits_all_strategies(
                n in 2..5usize,
            ) {
                let strategies: Vec<Box<dyn InputStrategy>> = (0..n)
                    .map(|i| {
                        let name: &'static str = match i % 4 {
                            0 => "alpha",
                            1 => "beta",
                            2 => "gamma",
                            _ => "delta",
                        };
                        Box::new(InfiniteNamedStrategy {
                            name,
                            value: vec![Value::from(i as i64)],
                        }) as Box<dyn InputStrategy>
                    })
                    .collect();

                let config = MetaConfig {
                    adaptive: false,
                    static_weights: None,
                    ..MetaConfig::default()
                };
                let mut meta = MetaStrategy::new(strategies, config);
                let ctx = empty_ctx();
                let mut rng = StdRng::seed_from_u64(42);

                // One full round: should visit each strategy exactly once.
                let mut visited = std::collections::HashSet::new();
                for _ in 0..n {
                    let (_, idx) = meta.next(&ctx, &mut rng).unwrap();
                    visited.insert(idx);
                }
                prop_assert_eq!(
                    visited.len(),
                    n,
                    "round-robin should visit all {} strategies in one round, visited {:?}",
                    n,
                    visited
                );
            }

            /// Adaptive mode never panics and always returns Some when
            /// non-exhausted strategies exist.
            #[test]
            fn adaptive_always_returns_when_non_exhausted(
                n in 1..5usize,
                config in arb_meta_config(),
                seed in any::<u64>(),
            ) {
                let strategies: Vec<Box<dyn InputStrategy>> = (0..n)
                    .map(|i| {
                        let name: &'static str = match i % 4 {
                            0 => "alpha",
                            1 => "beta",
                            2 => "gamma",
                            _ => "delta",
                        };
                        Box::new(InfiniteNamedStrategy {
                            name,
                            value: vec![Value::from(i as i64)],
                        }) as Box<dyn InputStrategy>
                    })
                    .collect();

                let config = MetaConfig { adaptive: true, ..config };
                let mut meta = MetaStrategy::new(strategies, config);
                let ctx = empty_ctx();
                let mut rng = StdRng::seed_from_u64(seed);

                // Should always produce candidates from infinite strategies.
                for _ in 0..10 {
                    let result = meta.next(&ctx, &mut rng);
                    prop_assert!(result.is_some(), "adaptive should return Some with non-exhausted strategies");
                }
            }

            /// Recording outcomes respects the window size: the window never
            /// exceeds config.window_size.
            #[test]
            fn window_size_bounded(
                window_size in 10..200usize,
                n_outcomes in 0..500usize,
                outcomes in pvec(any::<bool>(), 0..500),
            ) {
                let n_outcomes = n_outcomes.min(outcomes.len());
                let config = MetaConfig {
                    window_size,
                    ..MetaConfig::default()
                };
                let strategies: Vec<Box<dyn InputStrategy>> = vec![
                    Box::new(InfiniteNamedStrategy {
                        name: "test",
                        value: vec![Value::from(0)],
                    })
                ];
                let mut meta = MetaStrategy::new(strategies, config);

                for &outcome in &outcomes[..n_outcomes] {
                    meta.record_outcome(0, outcome);
                }

                prop_assert!(
                    meta.states[0].window.len() <= window_size,
                    "window size {} exceeds configured max {}",
                    meta.states[0].window.len(),
                    window_size
                );
            }
        }
    }
